#!/usr/bin/env bash
# Clean up a fixture dir generated by setup.sh.
#
# Usage: bash cleanup.sh <FIXTURE_DIR>
#
# Refuses to delete anything outside $HOME/.claude/projects/-tmp-eval-* to
# keep the script from accidentally nuking real session data on a typo.

set -euo pipefail

FIXTURE_DIR="${1:?Usage: cleanup.sh <FIXTURE_DIR>}"
EXPECTED_PREFIX="$HOME/.claude/projects/-tmp-eval-"

case "$FIXTURE_DIR" in
  "$EXPECTED_PREFIX"*)
    if [ -d "$FIXTURE_DIR" ]; then
      rm -rf "$FIXTURE_DIR"
      printf 'Removed %s\n' "$FIXTURE_DIR"
    else
      printf 'Already gone: %s\n' "$FIXTURE_DIR" >&2
    fi
    ;;
  *)
    printf 'Refusing to delete %s — must live under %s\n' "$FIXTURE_DIR" "$EXPECTED_PREFIX" >&2
    exit 1
    ;;
esac
